/**
 * Bundle @timephy/rnnoise-wasm into a single self-contained AudioWorklet script.
 * 
 * AudioWorklet modules can't use ES module imports, so we need to combine
 * all the pieces (polyfills, WASM module, processor, worklet) into one file.
 * 
 * Run: node scripts/bundle-rnnoise-worklet.js
 */

const fs = require('fs');
const path = require('path');

const distDir = path.join(__dirname, '..', 'node_modules', '@timephy', 'rnnoise-wasm', 'dist');
const outPath = path.join(__dirname, '..', 'public', 'rnnoise-suppressor.worklet.js');

// Verify the package exists
if (!fs.existsSync(distDir)) {
  console.error('❌ @timephy/rnnoise-wasm not found. Run: npm install');
  process.exit(1);
}

console.log('📦 Bundling @timephy/rnnoise-wasm for AudioWorklet...');

// 1. Read all source files
const polyfills = fs.readFileSync(path.join(distDir, 'polyfills.js'), 'utf-8');
const rnnoiseSync = fs.readFileSync(path.join(distDir, 'generated', 'rnnoise-sync.js'), 'utf-8');
const mathUtils = fs.readFileSync(path.join(distDir, 'math.js'), 'utf-8');
const processor = fs.readFileSync(path.join(distDir, 'RnnoiseProcessor.js'), 'utf-8');

// 2. Process each file to remove ES module syntax

// Polyfills: remove "use strict" (IIFE wrapper handles it)
const processedPolyfills = polyfills
  .replace(/^"use strict";\s*\n?/m, '');

// RNNoise sync module: 
// - Replace import.meta.url (not available in AudioWorkletGlobalScope)
// - Remove export default statement
const processedSync = rnnoiseSync
  .replace('var _scriptName = import.meta.url;', 'var _scriptName = "";')
  .replace(/\nexport\s+default\s+createRNNWasmModuleSync;\s*$/m, '');

// Math utilities: remove export keywords
const processedMath = mathUtils
  .replace(/^export function /gm, 'function ');

// RnnoiseProcessor: remove export keywords
const processedProcessor = processor
  .replace(/^export const /gm, 'const ')
  .replace(/^export default class /gm, 'class ');

// 3. Build the bundle
const bundle = `// @timephy/rnnoise-wasm v1.0.0 - Bundled for AudioWorklet
// Auto-generated by scripts/bundle-rnnoise-worklet.js - DO NOT EDIT MANUALLY
// Source: https://github.com/timephy/rnnoise-wasm
// License: Apache-2.0
(function() {
"use strict";

// ============================================
// Polyfills (atob + self.location.href)
// ============================================
${processedPolyfills}

// ============================================
// RNNoise WASM Module (Synchronous compilation)
// ============================================
${processedSync}

// ============================================
// Math Utilities
// ============================================
${processedMath}

// ============================================
// RNNoise Processor
// ============================================
${processedProcessor}

// ============================================
// Noise Suppressor AudioWorklet
// ============================================
var NoiseSuppressorWorklet_Name = "NoiseSuppressorWorklet";

class NoiseSuppressorWorklet extends AudioWorkletProcessor {
    constructor() {
        super();
        this._procNodeSampleRate = 128;
        this._denoiseProcessor = new RnnoiseProcessor(createRNNWasmModuleSync());
        this._denoiseSampleSize = this._denoiseProcessor.getSampleLength();
        this._circularBufferLength = leastCommonMultiple(this._procNodeSampleRate, this._denoiseSampleSize);
        this._circularBuffer = new Float32Array(this._circularBufferLength);
        this._inputBufferLength = 0;
        this._denoisedBufferLength = 0;
        this._denoisedBufferIndx = 0;
    }

    process(inputs, outputs) {
        var inData = inputs[0][0];
        var outData = outputs[0][0];
        if (!inData) return true;

        this._circularBuffer.set(inData, this._inputBufferLength);
        this._inputBufferLength += inData.length;

        for (; this._denoisedBufferLength + this._denoiseSampleSize <= this._inputBufferLength; this._denoisedBufferLength += this._denoiseSampleSize) {
            var denoiseFrame = this._circularBuffer.subarray(
                this._denoisedBufferLength,
                this._denoisedBufferLength + this._denoiseSampleSize
            );
            this._denoiseProcessor.processAudioFrame(denoiseFrame, true);
        }

        var unsentDenoisedDataLength;
        if (this._denoisedBufferIndx > this._denoisedBufferLength) {
            unsentDenoisedDataLength = this._circularBufferLength - this._denoisedBufferIndx;
        } else {
            unsentDenoisedDataLength = this._denoisedBufferLength - this._denoisedBufferIndx;
        }

        if (unsentDenoisedDataLength >= outData.length) {
            var denoisedFrame = this._circularBuffer.subarray(
                this._denoisedBufferIndx,
                this._denoisedBufferIndx + outData.length
            );
            outData.set(denoisedFrame, 0);
            this._denoisedBufferIndx += outData.length;
        }

        if (this._denoisedBufferIndx === this._circularBufferLength) {
            this._denoisedBufferIndx = 0;
        }

        if (this._inputBufferLength === this._circularBufferLength) {
            this._inputBufferLength = 0;
            this._denoisedBufferLength = 0;
        }

        return true;
    }
}

registerProcessor(NoiseSuppressorWorklet_Name, NoiseSuppressorWorklet);

})();
`;

fs.writeFileSync(outPath, bundle);
const stats = fs.statSync(outPath);
console.log('✅ Bundled rnnoise worklet written to: public/rnnoise-suppressor.worklet.js');
console.log('   Size: ' + (stats.size / 1024 / 1024).toFixed(2) + ' MB');
